def greet(*names, **kwargs):
    for name in names:
        print(f"Hello {name}")
    if "message" in kwargs:
        print(f"Message: {kwargs['message']}")

greet("Alice", "Bob", message="Welcome!")

add_ten = lambda x: x + 10
print(add_ten(5))

class Animal:
    def __init__(self, name):
        self.name = name
    def speak(self):
        raise NotImplementedError

class Dog(Animal):
    def speak(self):
        return f"{self.name} says Woof!"

my_dog = Dog("Buddy")
print(my_dog.speak())

